const raw = $input.first().json.content[0].text;
let audit = {};
try {
  audit = JSON.parse(raw);
} catch(e) {
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}') + 1;
  if (start >= 0 && end > start) {
    audit = JSON.parse(raw.substring(start, end));
  }
}
const gaps = audit.ranking_gaps || [];
return [{
  json: {
    record_id: $('Set Variables').item.json.record_id,
    verdict: audit.verdict || '',
    highest_leverage_fix: audit.highest_leverage_fix || '',
    personalization_hook: audit.personalization_hook || '',
    priority_score: audit.priority_score || 0,
    traffic_loss_level: (audit.estimated_traffic_loss || {}).level || '',
    traffic_loss_reasoning: (audit.estimated_traffic_loss || {}).reasoning || '',
    nationality_angle: audit.nationality_angle || null,
    ranking_gap_1: (gaps[0] || {}).gap || '',
    ranking_gap_2: (gaps[1] || {}).gap || '',
    ranking_gap_3: (gaps[2] || {}).gap || '',
    audit_timestamp: audit.audit_timestamp || new Date().toISOString(),
  }
}];
